# solution.py

"""
Multi-Agent Quest Creator

A system enabling multiple RPG players to collaboratively design, balance,
test, and share quests in real-time.
"""

import copy
import hashlib
import statistics
import time
import uuid
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Any, Optional


# --- Enums ---

class QuestType(Enum):
    COMBAT = "combat"
    PUZZLE = "puzzle"
    EXPLORATION = "exploration"
    HYBRID = "hybrid"


class Difficulty(Enum):
    EASY = 1
    MEDIUM = 2
    HARD = 3
    LEGENDARY = 4


class EnemyType(Enum):
    MELEE = "melee"
    RANGED = "ranged"
    MAGIC = "magic"
    BOSS = "boss"


class SimulationOutcome(Enum):
    SUCCESS = "success"
    FAILURE = "failure"
    PARTIAL = "partial"


# --- Data Models ---

@dataclass
class Player:
    player_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    username: str = ""
    skill_level: int = 1
    preferred_quest_types: list = field(default_factory=list)
    session_token: str = ""
    logged_in: bool = False
    contributions: int = 0

    def __post_init__(self):
        if not self.session_token:
            self.session_token = hashlib.sha256(
                f"{self.player_id}{time.time()}".encode()
            ).hexdigest()[:16]


@dataclass
class Enemy:
    enemy_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Unknown Enemy"
    enemy_type: EnemyType = EnemyType.MELEE
    health: int = 100
    attack: int = 10
    defense: int = 5
    special_abilities: list = field(default_factory=list)
    is_custom: bool = False

    @property
    def strength_score(self) -> float:
        base = self.health * 0.3 + self.attack * 0.4 + self.defense * 0.3
        ability_bonus = len(self.special_abilities) * 5
        boss_mult = 2.0 if self.enemy_type == EnemyType.BOSS else 1.0
        return (base + ability_bonus) * boss_mult


@dataclass
class Reward:
    reward_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Gold Coins"
    reward_type: str = "currency"
    value: int = 100
    rarity: str = "common"
    is_custom: bool = False


@dataclass
class Objective:
    objective_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    description: str = ""
    objective_type: str = "primary"
    completion_criteria: dict = field(default_factory=dict)
    is_optional: bool = False
    difficulty_weight: float = 1.0


@dataclass
class NPC:
    npc_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Unnamed NPC"
    role: str = "quest_giver"
    dialogue: list = field(default_factory=list)
    is_custom: bool = True
    created_by: str = ""


@dataclass
class CustomItem:
    item_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Custom Item"
    item_type: str = "weapon"
    stats: dict = field(default_factory=dict)
    description: str = ""
    created_by: str = ""


@dataclass
class QuestVersion:
    version_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    version_number: int = 1
    timestamp: str = field(default_factory=lambda: datetime.now().isoformat())
    snapshot: dict = field(default_factory=dict)
    change_description: str = ""
    changed_by: str = ""


@dataclass
class SimulationResult:
    simulation_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    outcome: SimulationOutcome = SimulationOutcome.SUCCESS
    duration_seconds: float = 0.0
    players_involved: list = field(default_factory=list)
    combat_rounds: int = 0
    damage_taken: float = 0.0
    damage_dealt: float = 0.0
    objectives_completed: int = 0
    total_objectives: int = 0
    balance_score: float = 0.0
    suggestions: list = field(default_factory=list)
    timestamp: str = field(default_factory=lambda: datetime.now().isoformat())


@dataclass
class QuestReview:
    review_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    quest_id: str = ""
    reviewer_id: str = ""
    rating: int = 5
    comment: str = ""
    timestamp: str = field(default_factory=lambda: datetime.now().isoformat())


@dataclass
class Quest:
    quest_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    title: str = "Untitled Quest"
    description: str = ""
    quest_type: QuestType = QuestType.COMBAT
    difficulty: Difficulty = Difficulty.MEDIUM
    objectives: list = field(default_factory=list)
    enemies: list = field(default_factory=list)
    rewards: list = field(default_factory=list)
    npcs: list = field(default_factory=list)
    custom_items: list = field(default_factory=list)
    collaborators: list = field(default_factory=list)
    created_by: str = ""
    created_at: str = field(default_factory=lambda: datetime.now().isoformat())
    is_published: bool = False
    shared_with_community: bool = False
    tags: list = field(default_factory=list)
    version_history: list = field(default_factory=list)
    simulation_results: list = field(default_factory=list)
    reviews: list = field(default_factory=list)

    @property
    def average_rating(self) -> float:
        if not self.reviews:
            return 0.0
        return statistics.mean(r.rating for r in self.reviews)

    @property
    def total_enemy_strength(self) -> float:
        return sum(e.strength_score for e in self.enemies)

    @property
    def total_reward_value(self) -> int:
        return sum(r.value for r in self.rewards)


# --- Balance Engine ---

class BalanceEngine:
    """Analyzes quest balance and provides adjustment suggestions."""

    DIFFICULTY_THRESHOLDS = {
        Difficulty.EASY: (0, 150),
        Difficulty.MEDIUM: (150, 400),
        Difficulty.HARD: (400, 800),
        Difficulty.LEGENDARY: (800, float("inf")),
    }

    REWARD_RATIOS = {
        Difficulty.EASY: 0.5,
        Difficulty.MEDIUM: 1.0,
        Difficulty.HARD: 1.8,
        Difficulty.LEGENDARY: 3.0,
    }

    def analyze_balance(self, quest: Quest, players: list) -> dict:
        """Analyze overall quest balance given the participating players."""
        enemy_strength = quest.total_enemy_strength
        avg_skill = (
            statistics.mean(p.skill_level for p in players) if players else 1
        )
        party_size = len(players) if players else 1

        effective_party_power = avg_skill * party_size * 50
        difficulty_ratio = (
            enemy_strength / effective_party_power if effective_party_power > 0 else 0
        )

        target_low, target_high = self.DIFFICULTY_THRESHOLDS[quest.difficulty]
        expected_ratio = self._expected_ratio(quest.difficulty)
        balance_score = max(0, 100 - abs(difficulty_ratio - expected_ratio) * 100)

        reward_balance = self._check_reward_balance(quest)
        objective_balance = self._check_objective_balance(quest)

        suggestions = self._generate_suggestions(
            quest, players, difficulty_ratio, expected_ratio,
            reward_balance, objective_balance
        )

        return {
            "balance_score": round(balance_score, 1),
            "difficulty_ratio": round(difficulty_ratio, 2),
            "expected_ratio": expected_ratio,
            "enemy_strength_total": enemy_strength,
            "party_power": effective_party_power,
            "reward_balance": reward_balance,
            "objective_balance": objective_balance,
            "suggestions": suggestions,
            "is_balanced": balance_score >= 60,
        }

    def _expected_ratio(self, difficulty: Difficulty) -> float:
        return {
            Difficulty.EASY: 0.5,
            Difficulty.MEDIUM: 1.0,
            Difficulty.HARD: 1.5,
            Difficulty.LEGENDARY: 2.5,
        }[difficulty]

    def _check_reward_balance(self, quest: Quest) -> dict:
        total_reward = quest.total_reward_value
        expected_reward = int(quest.total_enemy_strength * self.REWARD_RATIOS[quest.difficulty])
        deviation = abs(total_reward - expected_reward) / max(expected_reward, 1) * 100

        return {
            "total_reward_value": total_reward,
            "expected_reward_value": expected_reward,
            "deviation_percent": round(deviation, 1),
            "is_balanced": deviation < 30,
        }

    def _check_objective_balance(self, quest: Quest) -> dict:
        total = len(quest.objectives)
        optional_count = sum(1 for o in quest.objectives if o.is_optional)
        primary_count = total - optional_count
        weighted_difficulty = sum(o.difficulty_weight for o in quest.objectives)

        return {
            "total_objectives": total,
            "primary_objectives": primary_count,
            "optional_objectives": optional_count,
            "weighted_difficulty": round(weighted_difficulty, 1),
            "is_balanced": 1 <= primary_count <= 5 and weighted_difficulty < 10,
        }

    def _generate_suggestions(
        self, quest, players, ratio, expected, reward_bal, obj_bal
    ) -> list:
        suggestions = []

        if ratio > expected * 1.3:
            suggestions.append({
                "type": "reduce_difficulty",
                "message": "Quest is too hard for current party. Consider reducing enemies.",
                "action": "remove_enemy",
                "priority": "high",
            })
        elif ratio < expected * 0.7:
            suggestions.append({
                "type": "increase_difficulty",
                "message": "Quest is too easy. Consider adding more enemies or raising their stats.",
                "action": "add_enemy",
                "priority": "medium",
            })

        if not reward_bal["is_balanced"]:
            if reward_bal["total_reward_value"] < reward_bal["expected_reward_value"]:
                suggestions.append({
                    "type": "increase_rewards",
                    "message": "Rewards are below expected value for this difficulty.",
                    "action": "add_reward",
                    "priority": "medium",
                })
            else:
                suggestions.append({
                    "type": "reduce_rewards",
                    "message": "Rewards exceed expected value. May feel unbalanced.",
                    "action": "reduce_reward",
                    "priority": "low",
                })

        if not obj_bal["is_balanced"]:
            if obj_bal["primary_objectives"] > 5:
                suggestions.append({
                    "type": "reduce_objectives",
                    "message": "Too many primary objectives may overwhelm players.",
                    "action": "make_optional",
                    "priority": "medium",
                })
            elif obj_bal["primary_objectives"] < 1:
                suggestions.append({
                    "type": "add_objectives",
                    "message": "Quest needs at least one primary objective.",
                    "action": "add_objective",
                    "priority": "high",
                })

        if quest.quest_type == QuestType.COMBAT and not quest.enemies:
            suggestions.append({
                "type": "add_enemies",
                "message": "Combat quest has no enemies defined.",
                "action": "add_enemy",
                "priority": "high",
            })

        return suggestions

    def suggest_enemy_adjustments(self, quest: Quest, players: list) -> list:
        """Suggest specific enemy modifications."""
        suggestions = []
        avg_skill = statistics.mean(p.skill_level for p in players) if players else 1

        for enemy in quest.enemies:
            if enemy.strength_score > avg_skill * 100:
                suggestions.append({
                    "enemy": enemy.name,
                    "suggestion": "Reduce health or attack",
                    "current_strength": enemy.strength_score,
                    "recommended_max": avg_skill * 80,
                })
            elif enemy.strength_score < avg_skill * 20:
                suggestions.append({
                    "enemy": enemy.name,
                    "suggestion": "Increase stats or add abilities",
                    "current_strength": enemy.strength_score,
                    "recommended_min": avg_skill * 30,
                })

        return suggestions


# --- Simulation Engine ---

class SimulationEngine:
    """Simulates quest execution to provide balance data."""

    def simulate(self, quest: Quest, players: list) -> SimulationResult:
        """Run a quest simulation and return results."""
        party_power = sum(p.skill_level * 50 for p in players)
        enemy_power = quest.total_enemy_strength

        combat_rounds = max(1, int(enemy_power / max(party_power * 0.3, 1)))
        damage_dealt = party_power * combat_rounds * 0.8
        damage_taken = enemy_power * 0.6

        survival_ratio = party_power / max(enemy_power, 1)
        if survival_ratio > 1.5:
            outcome = SimulationOutcome.SUCCESS
        elif survival_ratio > 0.7:
            outcome = SimulationOutcome.PARTIAL
        else:
            outcome = SimulationOutcome.FAILURE

        objectives_completed = self._simulate_objectives(quest, players, outcome)
        duration = combat_rounds * 15.0 + len(quest.objectives) * 30.0

        balance_score = self._calculate_balance_score(
            survival_ratio, objectives_completed, len(quest.objectives)
        )

        suggestions = self._derive_suggestions(quest, balance_score, outcome, survival_ratio)

        result = SimulationResult(
            outcome=outcome,
            duration_seconds=duration,
            players_involved=[p.username for p in players],
            combat_rounds=combat_rounds,
            damage_taken=damage_taken,
            damage_dealt=damage_dealt,
            objectives_completed=objectives_completed,
            total_objectives=len(quest.objectives),
            balance_score=balance_score,
            suggestions=suggestions,
        )

        quest.simulation_results.append(result)
        return result

    def _simulate_objectives(self, quest, players, outcome) -> int:
        if outcome == SimulationOutcome.SUCCESS:
            return len(quest.objectives)
        elif outcome == SimulationOutcome.PARTIAL:
            return max(1, len(quest.objectives) // 2)
        return 0

    def _calculate_balance_score(self, survival_ratio, completed, total) -> float:
        combat_score = max(0, 100 - abs(survival_ratio - 1.0) * 50)
        obj_score = (completed / max(total, 1)) * 100
        return round((combat_score * 0.6 + obj_score * 0.4), 1)

    def _derive_suggestions(self, quest, score, outcome, ratio) -> list:
        suggestions = []
        if outcome == SimulationOutcome.FAILURE:
            suggestions.append("Reduce enemy count or strength for better player experience.")
        if ratio > 2.5:
            suggestions.append("Quest is too easy. Consider increasing difficulty.")
        if score < 50:
            suggestions.append("Balance score is low. Review enemy-to-reward ratio.")
        if not quest.objectives:
            suggestions.append("Add objectives to give players clear goals.")
        return suggestions


# --- History Manager ---

class HistoryManager:
    """Tracks quest versions and enables rollback."""

    def save_version(self, quest: Quest, change_description: str, changed_by: str) -> QuestVersion:
        """Save a snapshot of the current quest state."""
        snapshot = {
            "title": quest.title,
            "description": quest.description,
            "quest_type": quest.quest_type.value,
            "difficulty": quest.difficulty.value,
            "objectives": [vars(o) for o in quest.objectives],
            "enemies": [
                {**vars(e), "enemy_type": e.enemy_type.value}
                for e in quest.enemies
            ],
            "rewards": [vars(r) for r in quest.rewards],
            "npcs": [vars(n) for n in quest.npcs],
            "custom_items": [vars(i) for i in quest.custom_items],
            "tags": list(quest.tags),
        }

        version_number = len(quest.version_history) + 1
        version = QuestVersion(
            version_number=version_number,
            snapshot=snapshot,
            change_description=change_description,
            changed_by=changed_by,
        )
        quest.version_history.append(version)
        return version

    def revert_to_version(self, quest: Quest, version_number: int) -> bool:
        """Revert quest to a specific version."""
        target = None
        for v in quest.version_history:
            if v.version_number == version_number:
                target = v
                break

        if target is None:
            return False

        snap = target.snapshot
        quest.title = snap["title"]
        quest.description = snap["description"]
        quest.quest_type = QuestType(snap["quest_type"])
        quest.difficulty = Difficulty(snap["difficulty"])

        quest.objectives = [
            Objective(**o) for o in snap.get("objectives", [])
        ]
        quest.enemies = [
            Enemy(**{**e, "enemy_type": EnemyType(e["enemy_type"])})
            for e in snap.get("enemies", [])
        ]
        quest.rewards = [Reward(**r) for r in snap.get("rewards", [])]
        quest.npcs = [NPC(**n) for n in snap.get("npcs", [])]
        quest.custom_items = [CustomItem(**i) for i in snap.get("custom_items", [])]
        quest.tags = snap.get("tags", [])

        return True

    def get_history(self, quest: Quest) -> list:
        """Return full version history."""
        return [
            {
                "version": v.version_number,
                "timestamp": v.timestamp,
                "description": v.change_description,
                "changed_by": v.changed_by,
            }
            for v in quest.version_history
        ]

    def diff_versions(self, quest: Quest, v1: int, v2: int) -> dict:
        """Compare two versions and return differences."""
        snap1 = snap2 = None
        for v in quest.version_history:
            if v.version_number == v1:
                snap1 = v.snapshot
            if v.version_number == v2:
                snap2 = v.snapshot

        if snap1 is None or snap2 is None:
            return {"error": "Version not found"}

        changes = {}
        for key in snap1:
            if snap1[key] != snap2.get(key):
                changes[key] = {"from": snap1[key], "to": snap2.get(key)}
        return changes


# --- Community Sharing ---

class CommunityHub:
    """Handles quest sharing, rating, and reviewing."""

    def __init__(self):
        self.shared_quests: dict[str, Quest] = {}
        self.reviews: list[QuestReview] = []

    def publish_quest(self, quest: Quest) -> dict:
        """Publish a quest to the community."""
        quest.is_published = True
        quest.shared_with_community = True
        self.shared_quests[quest.quest_id] = quest
        return {
            "status": "published",
            "quest_id": quest.quest_id,
            "title": quest.title,
        }

    def unpublish_quest(self, quest_id: str) -> bool:
        """Remove a quest from community sharing."""
        if quest_id in self.shared_quests:
            self.shared_quests[quest_id].shared_with_community = False
            del self.shared_quests[quest_id]
            return True
        return False

    def rate_quest(self, quest_id: str, reviewer_id: str, rating: int, comment: str = "") -> Optional[QuestReview]:
        """Rate and review a shared quest."""
        if quest_id not in self.shared_quests:
            return None
        if not 1 <= rating <= 5:
            return None

        review = QuestReview(
            quest_id=quest_id,
            reviewer_id=reviewer_id,
            rating=rating,
            comment=comment,
        )
        self.shared_quests[quest_id].reviews.append(review)
        self.reviews.append(review)
        return review

    def get_top_quests(self, limit: int = 10) -> list:
        """Get highest-rated community quests."""
        rated = [
            (q, q.average_rating)
            for q in self.shared_quests.values()
            if q.reviews
        ]
        rated.sort(key=lambda x: x[1], reverse=True)
        return [
            {
                "quest_id": q.quest_id,
                "title": q.title,
                "rating": round(r, 1),
                "review_count": len(q.reviews),
                "quest_type": q.quest_type.value,
            }
            for q, r in rated[:limit]
        ]

    def search_quests(self, query: str = "", quest_type: Optional[QuestType] = None, min_rating: float = 0) -> list:
        """Search shared quests with filters."""
        results = []
        for quest in self.shared_quests.values():
            if query and query.lower() not in quest.title.lower() and query.lower() not in quest.description.lower():
                continue
            if quest_type and quest.quest_type != quest_type:
                continue
            if min_rating > 0 and quest.average_rating < min_rating:
                continue
            results.append({
                "quest_id": quest.quest_id,
                "title": quest.title,
                "description": quest.description,
                "quest_type": quest.quest_type.value,
                "difficulty": quest.difficulty.name,
                "rating": quest.average_rating,
                "review_count": len(quest.reviews),
            })
        return results


# --- Feedback Adapter ---

class FeedbackAdapter:
    """Adapts quest parameters based on player feedback and simulation data."""

    def apply_feedback(self, quest: Quest, feedback: dict) -> list:
        """Process player feedback and suggest or apply modifications."""
        modifications = []

        if "too_hard" in feedback.get("tags", []):
            modifications.extend(self._ease_difficulty(quest))
        if "too_easy" in feedback.get("tags", []):
            modifications.extend(self._increase_difficulty(quest))
        if "boring_rewards" in feedback.get("tags", []):
            modifications.extend(self._improve_rewards(quest))
        if "too_long" in feedback.get("tags", []):
            modifications.extend(self._shorten_quest(quest))
        if "not_enough_variety" in feedback.get("tags", []):
            modifications.extend(self._add_variety(quest))

        if feedback.get("preferred_enemy_types"):
            modifications.extend(
                self._adjust_enemy_types(quest, feedback["preferred_enemy_types"])
            )

        return modifications

    def _ease_difficulty(self, quest: Quest) -> list:
        mods = []
        for enemy in quest.enemies:
            enemy.health = int(enemy.health * 0.8)
            enemy.attack = int(enemy.attack * 0.85)
            mods.append(f"Reduced {enemy.name} stats (health -20%, attack -15%)")
        if quest.difficulty.value > 1:
            new_diff = Difficulty(quest.difficulty.value - 1)
            quest.difficulty = new_diff
            mods.append(f"Lowered difficulty to {new_diff.name}")
        return mods

    def _increase_difficulty(self, quest: Quest) -> list:
        mods = []
        for enemy in quest.enemies:
            enemy.health = int(enemy.health * 1.2)
            enemy.attack = int(enemy.attack * 1.15)
            mods.append(f"Increased {enemy.name} stats (health +20%, attack +15%)")
        if quest.difficulty.value < 4:
            new_diff = Difficulty(quest.difficulty.value + 1)
            quest.difficulty = new_diff
            mods.append(f"Raised difficulty to {new_diff.name}")
        return mods

    def _improve_rewards(self, quest: Quest) -> list:
        mods = []
        for reward in quest.rewards:
            reward.value = int(reward.value * 1.5)
            mods.append(f"Increased {reward.name} value by 50%")
        if not quest.rewards:
            new_reward = Reward(name="Bonus Gold", value=200, rarity="uncommon")
            quest.rewards.append(new_reward)
            mods.append("Added Bonus Gold reward")
        return mods

    def _shorten_quest(self, quest: Quest) -> list:
        mods = []
        optional = [o for o in quest.objectives if o.is_optional]
        if optional:
            removed = optional[0]
            quest.objectives.remove(removed)
            mods.append(f"Removed optional objective: {removed.description}")
        elif len(quest.enemies) > 2:
            removed = quest.enemies.pop()
            mods.append(f"Removed enemy: {removed.name}")
        return mods

    def _add_variety(self, quest: Quest) -> list:
        mods = []
        existing_types = {e.enemy_type for e in quest.enemies}
        missing = set(EnemyType) - existing_types
        if missing:
            new_type = missing.pop()
            new_enemy = Enemy(
                name=f"{new_type.value.title()} Foe",
                enemy_type=new_type,
                health=80,
                attack=12,
                defense=6,
            )
            quest.enemies.append(new_enemy)
            mods.append(f"Added {new_type.value} enemy for variety")
        return mods

    def _adjust_enemy_types(self, quest: Quest, preferred: list) -> list:
        mods = []
        for enemy in quest.enemies:
            for pref in preferred:
                try:
                    pref_type = EnemyType(pref)
                    if enemy.enemy_type != pref_type and len(quest.enemies) > 1:
                        enemy.enemy_type = pref_type
                        mods.append(f"Changed {enemy.name} to {pref_type.value} type")
                        break
                except ValueError:
                    continue
        return mods


# --- Session Manager ---

class SessionManager:
    """Manages collaborative editing sessions."""

    def __init__(self):
        self.active_sessions: dict[str, dict] = {}

    def create_session(self, quest: Quest, host: Player) -> str:
        """Create a new collaborative session."""
        session_id = str(uuid.uuid4())
        self.active_sessions[session_id] = {
            "session_id": session_id,
            "quest_id": quest.quest_id,
            "host": host.player_id,
            "participants": [host.player_id],
            "created_at": datetime.now().isoformat(),
            "changes_log": [],
            "is_active": True,
        }
        return session_id

    def join_session(self, session_id: str, player: Player) -> bool:
        """Add a player to an active session."""
        if session_id not in self.active_sessions:
            return False
        session = self.active_sessions[session_id]
        if not session["is_active"]:
            return False
        if player.player_id not in session["participants"]:
            session["participants"].append(player.player_id)
        return True

    def leave_session(self, session_id: str, player_id: str) -> bool:
        """Remove a player from a session."""
        if session_id not in self.active_sessions:
            return False
        session = self.active_sessions[session_id]
        if player_id in session["participants"]:
            session["participants"].remove(player_id)
            return True
        return False

    def log_change(self, session_id: str, player_id: str, change: str):
        """Record a change made during the session."""
        if session_id in self.active_sessions:
            self.active_sessions[session_id]["changes_log"].append({
                "player_id": player_id,
                "change": change,
                "timestamp": datetime.now().isoformat(),
            })

    def close_session(self, session_id: str) -> bool:
        """Close a collaborative session."""
        if session_id in self.active_sessions:
            self.active_sessions[session_id]["is_active"] = False
            return True
        return False

    def get_session_info(self, session_id: str) -> Optional[dict]:
        """Get session details."""
        return self.active_sessions.get(session_id)


# --- Main System ---

class MultiAgentQuestCreator:
    """
    Main system coordinating quest creation, collaboration, balancing,
    simulation, history, and community sharing.
    """

    def __init__(self):
        self.players: dict[str, Player] = {}
        self.quests: dict[str, Quest] = {}
        self.balance_engine = BalanceEngine()
        self.simulation_engine = SimulationEngine()
        self.history_manager = HistoryManager()
        self.community_hub = CommunityHub()
        self.feedback_adapter = FeedbackAdapter()
        self.session_manager = SessionManager()

    # --- Player Management ---

    def register_player(self, username: str, skill_level: int = 1, preferred_types: Optional[list] = None) -> Player:
        """Register a new player."""
        player = Player(
            username=username,
            skill_level=max(1, min(skill_level, 100)),
            preferred_quest_types=preferred_types or [],
        )
        self.players[player.player_id] = player
        return player

    def login_player(self, player_id: str) -> Optional[Player]:
        """Log in an existing player."""
        player = self.players.get(player_id)
        if player:
            player.logged_in = True
            player.session_token = hashlib.sha256(
                f"{player_id}{time.time()}".encode()
            ).hexdigest()[:16]
        return player

    def logout_player(self, player_id: str) -> bool:
        """Log out a player."""
        player = self.players.get(player_id)
        if player:
            player.logged_in = False
            player.session_token = ""
            return True
        return False

    def get_player(self, player_id: str) -> Optional[Player]:
        """Retrieve a player by ID."""
        return self.players.get(player_id)

    # --- Quest Creation & Management ---

    def create_quest(
        self,
        creator_id: str,
        title: str,
        description: str = "",
        quest_type: QuestType = QuestType.COMBAT,
        difficulty: Difficulty = Difficulty.MEDIUM,
    ) -> Optional[Quest]:
        """Create a new quest."""
        creator = self.players.get(creator_id)
        if not creator or not creator.logged_in:
            return None

        quest = Quest(
            title=title,
            description=description,
            quest_type=quest_type,
            difficulty=difficulty,
            created_by=creator_id,
            collaborators=[creator_id],
        )
        self.quests[quest.quest_id] = quest
        creator.contributions += 1

        self.history_manager.save_version(quest, "Initial creation", creator.username)
        return quest

    def add_collaborator(self, quest_id: str, player_id: str) -> bool:
        """Add a player as collaborator on a quest."""
        quest = self.quests.get(quest_id)
        player = self.players.get(player_id)
        if not quest or not player or not player.logged_in:
            return False
        if player_id not in quest.collaborators:
            quest.collaborators.append(player_id)
        return True

    def add_objective(self, quest_id: str, player_id: str, description: str,
                      objective_type: str = "primary", is_optional: bool = False,
                      difficulty_weight: float = 1.0) -> Optional[Objective]:
        """Add an objective to a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return None

        objective = Objective(
            description=description,
            objective_type=objective_type,
            is_optional=is_optional,
            difficulty_weight=difficulty_weight,
        )
        quest.objectives.append(objective)

        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(
            quest, f"Added objective: {description}", username
        )
        return objective

    def add_enemy(self, quest_id: str, player_id: str, name: str,
                  enemy_type: EnemyType = EnemyType.MELEE, health: int = 100,
                  attack: int = 10, defense: int = 5,
                  special_abilities: Optional[list] = None,
                  is_custom: bool = False) -> Optional[Enemy]:
        """Add an enemy to a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return None

        enemy = Enemy(
            name=name,
            enemy_type=enemy_type,
            health=health,
            attack=attack,
            defense=defense,
            special_abilities=special_abilities or [],
            is_custom=is_custom,
        )
        quest.enemies.append(enemy)

        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(quest, f"Added enemy: {name}", username)
        return enemy

    def add_reward(self, quest_id: str, player_id: str, name: str,
                   reward_type: str = "currency", value: int = 100,
                   rarity: str = "common", is_custom: bool = False) -> Optional[Reward]:
        """Add a reward to a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return None

        reward = Reward(
            name=name,
            reward_type=reward_type,
            value=value,
            rarity=rarity,
            is_custom=is_custom,
        )
        quest.rewards.append(reward)

        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(quest, f"Added reward: {name}", username)
        return reward

    def add_npc(self, quest_id: str, player_id: str, name: str,
                role: str = "quest_giver", dialogue: Optional[list] = None) -> Optional[NPC]:
        """Add a custom NPC to a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return None

        npc = NPC(
            name=name,
            role=role,
            dialogue=dialogue or [],
            created_by=player_id,
        )
        quest.npcs.append(npc)

        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(quest, f"Added NPC: {name}", username)
        return npc

    def add_custom_item(self, quest_id: str, player_id: str, name: str,
                        item_type: str = "weapon", stats: Optional[dict] = None,
                        description: str = "") -> Optional[CustomItem]:
        """Add a custom item to a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return None

        item = CustomItem(
            name=name,
            item_type=item_type,
            stats=stats or {},
            description=description,
            created_by=player_id,
        )
        quest.custom_items.append(item)

        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(quest, f"Added custom item: {name}", username)
        return item

    def remove_enemy(self, quest_id: str, player_id: str, enemy_id: str) -> bool:
        """Remove an enemy from a quest."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return False
        for enemy in quest.enemies:
            if enemy.enemy_id == enemy_id:
                quest.enemies.remove(enemy)
                player = self.players.get(player_id)
                username = player.username if player else "unknown"
                self.history_manager.save_version(
                    quest, f"Removed enemy: {enemy.name}", username
                )
                return True
        return False

    def update_difficulty(self, quest_id: str, player_id: str, difficulty: Difficulty) -> bool:
        """Update quest difficulty level."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return False
        quest.difficulty = difficulty
        player = self.players.get(player_id)
        username = player.username if player else "unknown"
        self.history_manager.save_version(
            quest, f"Changed difficulty to {difficulty.name}", username
        )
        return True

    # --- Balance & Feedback ---

    def get_balance_report(self, quest_id: str, player_ids: Optional[list] = None) -> Optional[dict]:
        """Get a balance analysis for a quest."""
        quest = self.quests.get(quest_id)
        if not quest:
            return None

        if player_ids:
            players = [self.players[pid] for pid in player_ids if pid in self.players]
        else:
            players = [self.players[pid] for pid in quest.collaborators if pid in self.players]

        return self.balance_engine.analyze_balance(quest, players)

    def get_enemy_suggestions(self, quest_id: str, player_ids: Optional[list] = None) -> list:
        """Get specific enemy adjustment suggestions."""
        quest = self.quests.get(quest_id)
        if not quest:
            return []
        if player_ids:
            players = [self.players[pid] for pid in player_ids if pid in self.players]
        else:
            players = [self.players[pid] for pid in quest.collaborators if pid in self.players]
        return self.balance_engine.suggest_enemy_adjustments(quest, players)

    def submit_feedback(self, quest_id: str, player_id: str, feedback: dict) -> list:
        """Submit feedback to adapt quest parameters."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return []

        modifications = self.feedback_adapter.apply_feedback(quest, feedback)

        if modifications:
            player = self.players.get(player_id)
            username = player.username if player else "unknown"
            self.history_manager.save_version(
                quest, f"Applied feedback: {', '.join(feedback.get('tags', []))}", username
            )

        return modifications

    # --- Simulation ---

    def run_simulation(self, quest_id: str, player_ids: Optional[list] = None) -> Optional[SimulationResult]:
        """Run a quest simulation."""
        quest = self.quests.get(quest_id)
        if not quest:
            return None

        if player_ids:
            players = [self.players[pid] for pid in player_ids if pid in self.players]
        else:
            players = [self.players[pid] for pid in quest.collaborators if pid in self.players]

        if not players:
            return None

        return self.simulation_engine.simulate(quest, players)

    # --- History ---

    def get_quest_history(self, quest_id: str) -> list:
        """Get version history of a quest."""
        quest = self.quests.get(quest_id)
        if not quest:
            return []
        return self.history_manager.get_history(quest)

    def revert_quest(self, quest_id: str, player_id: str, version_number: int) -> bool:
        """Revert a quest to a previous version."""
        quest = self.quests.get(quest_id)
        if not quest or player_id not in quest.collaborators:
            return False

        success = self.history_manager.revert_to_version(quest, version_number)
        if success:
            player = self.players.get(player_id)
            username = player.username if player else "unknown"
            self.history_manager.save_version(
                quest, f"Reverted to version {version_number}", username
            )
        return success

    def diff_quest_versions(self, quest_id: str, v1: int, v2: int) -> dict:
        """Compare two versions of a quest."""
        quest = self.quests.get(quest_id)
        if not quest:
            return {"error": "Quest not found"}
        return self.history_manager.diff_versions(quest, v1, v2)

    # --- Collaboration Sessions ---

    def start_collaboration_session(self, quest_id: str, host_id: str) -> Optional[str]:
        """Start a real-time collaboration session."""
        quest = self.quests.get(quest_id)
        host = self.players.get(host_id)
        if not quest or not host or not host.logged_in:
            return None
        if host_id not in quest.collaborators:
            return None
        return self.session_manager.create_session(quest, host)

    def join_collaboration_session(self, session_id: str, player_id: str) -> bool:
        """Join an existing collaboration session."""
        player = self.players.get(player_id)
        if not player or not player.logged_in:
            return False
        return self.session_manager.join_session(session_id, player)

    def leave_collaboration_session(self, session_id: str, player_id: str) -> bool:
        """Leave a collaboration session."""
        return self.session_manager.leave_session(session_id, player_id)

    # --- Community Sharing ---

    def publish_quest(self, quest_id: str, player_id: str) -> Optional[dict]:
        """Publish a quest to the community."""
        quest = self.quests.get(quest_id)
        if not quest or quest.created_by != player_id:
            return None
        return self.community_hub.publish_quest(quest)

    def unpublish_quest(self, quest_id: str, player_id: str) -> bool:
        """Remove a quest from community sharing."""
        quest = self.quests.get(quest_id)
        if not quest or quest.created_by != player_id:
            return False
        return self.community_hub.unpublish_quest(quest_id)

    def rate_quest(self, quest_id: str, reviewer_id: str, rating: int, comment: str = "") -> Optional[QuestReview]:
        """Rate and review a community quest."""
        return self.community_hub.rate_quest(quest_id, reviewer_id, rating, comment)

    def get_top_community_quests(self, limit: int = 10) -> list:
        """Get highest-rated quests from the community."""
        return self.community_hub.get_top_quests(limit)

    def search_community_quests(self, query: str = "", quest_type: Optional[QuestType] = None, min_rating: float = 0) -> list:
        """Search community quests."""
        return self.community_hub.search_quests(query, quest_type, min_rating)

    # --- Utility ---

    def get_quest(self, quest_id: str) -> Optional[Quest]:
        """Retrieve a quest by ID."""
        return self.quests.get(quest_id)

    def list_quests(self, creator_id: Optional[str] = None) -> list:
        """List quests, optionally filtered by creator."""
        quests = self.quests.values()
        if creator_id:
            quests = [q for q in quests if creator_id in q.collaborators]
        return [
            {
                "quest_id": q.quest_id,
                "title": q.title,
                "quest_type": q.quest_type.value,
                "difficulty": q.difficulty.name,
                "collaborator_count": len(q.collaborators),
                "is_published": q.is_published,
            }
            for q in quests
        ]

    def get_quest_summary(self, quest_id: str) -> Optional[dict]:
        """Get a summary of a quest's current state."""
        quest = self.quests.get(quest_id)
        if not quest:
            return None
        return {
            "quest_id": quest.quest_id,
            "title": quest.title,
            "description": quest.description,
            "quest_type": quest.quest_type.value,
            "difficulty": quest.difficulty.name,
            "objectives_count": len(quest.objectives),
            "enemies_count": len(quest.enemies),
            "rewards_count": len(quest.rewards),
            "npcs_count": len(quest.npcs),
            "custom_items_count": len(quest.custom_items),
            "collaborators_count": len(quest.collaborators),
            "version_count": len(quest.version_history),
            "simulation_count": len(quest.simulation_results),
            "is_published": quest.is_published,
            "average_rating": quest.average_rating,
            "total_enemy_strength": quest.total_enemy_strength,
            "total_reward_value": quest.total_reward_value,
        }


