def demo():
    """Demonstrate Multi-Agent Quest Creator functionality."""
    system = MultiAgentQuestCreator()

    # Register players
    alice = system.register_player("Alice", skill_level=5, preferred_types=["combat"])
    bob = system.register_player("Bob", skill_level=3, preferred_types=["puzzle"])
    charlie = system.register_player("Charlie", skill_level=7, preferred_types=["exploration"])

    # Login
    system.login_player(alice.player_id)
    system.login_player(bob.player_id)
    system.login_player(charlie.player_id)

    # Create a quest
    quest = system.create_quest(
        alice.player_id,
        "The Dragon's Lair",
        "Brave adventurers must infiltrate the dragon's lair and retrieve the stolen artifact.",
        QuestType.COMBAT,
        Difficulty.HARD,
    )
    print(f"Created quest: {quest.title} (ID: {quest.quest_id})")

    # Add collaborators
    system.add_collaborator(quest.quest_id, bob.player_id)
    system.add_collaborator(quest.quest_id, charlie.player_id)

    # Add objectives
    system.add_objective(quest.quest_id, alice.player_id, "Defeat the Dragon Guardian", "primary")
