    system.add_reward(quest.quest_id, bob.player_id, "Ancient Artifact", "item", 1000, "legendary")

    # Add custom content
    system.add_npc(quest.quest_id, bob.player_id, "Old Hermit", "guide", ["The dragon sleeps at dusk..."])
    system.add_custom_item(quest.quest_id, charlie.player_id, "Shadow Cloak", "armor", {"defense": 10, "stealth": 5}, "A cloak woven from shadows")

    # Check balance
    print("\n--- Balance Report ---")
    balance = system.get_balance_report(quest.quest_id)
    print(f"Balance Score: {balance['balance_score']}")
    print(f"Is Balanced: {balance['is_balanced']}")
    for suggestion in balance["suggestions"]:
        print(f"  [{suggestion['priority']}] {suggestion['message']}")

    # Run simulation
    print("\n--- Simulation ---")
    sim_result = system.run_simulation(quest.quest_id)
    print(f"Outcome: {sim_result.outcome.value}")
    print(f"Combat Rounds: {sim_result.combat_rounds}")
    print(f"Balance Score: {sim_result.balance_score}")
    for s in sim_result.suggestions:
        print(f"  Suggestion: {s}")

    # Submit feedback
    print("\n--- Feedback Applied ---")
    mods = system.submit_feedback(quest.quest_id, alice.player_id, {"tags": ["too_hard"]})
    for mod in mods:
        print(f"  {mod}")

    # Check version history
    print("\n--- Version History ---")
    history = system.get_quest_history(quest.quest_id)
    for entry in history:
        print(f"  v{entry['version']}: {entry['description']} (by {entry['changed_by']})")

    # Revert to earlier version
    system.revert_quest(quest.quest_id, alice.player_id, 3)
